mapper.select:
SELECT maLuongTuyen, doPhucTap, khoangCachTu, khoangCachDen, luongCoBan
FROM LuongTuyenDuong
WHERE maLuongTuyen = #{maLuongTuyen}

mapper.update:
UPDATE LuongTuyenDuong
SET doPhucTap = #{doPhucTap},
    khoangCachTu = #{khoangCachTu},
    khoangCachDen = #{khoangCachDen},
    luongCoBan = #{luongCoBan}

WHERE maLuongTuyen = #{maLuongTuyen}

mapper.select:
SELECT maLuongTuyen
FROM LuongTuyenDuong
WHERE doPhucTap = #{doPhucTap}
AND khoangCachDen >= #{khoangCach}
AND #{khoangCach} >= khoangCachTu

SELECT *
FROM LuongTuyenDuong
WHERE doPhucTap = #{doPhucTap}
AND khoangCachDen >= #{khoangCach}
AND #{khoangCach} >= khoangCachTu
